oldWay:
/* Bad pattern 1: Remove focus for everyone (accessibility failure) */
.button:focus { outline: none; }

/* Bad pattern 2: JavaScript to track mouse vs keyboard */
document.addEventListener('mousedown', () => {
  document.body.classList.add('using-mouse');
});
document.addEventListener('keydown', () => {
  document.body.classList.remove('using-mouse');
});
.button:focus { outline: 2px solid #a855f7; }
.using-mouse .button:focus { outline: none; }

startingCSS:
.container {
  padding: 1.5rem;
  background: #1e293b;
  border-radius: 10px;
}

.hint {
  color: #64748b;
  font-size: 0.78rem;
  margin: 0 0 1rem;
}

.row {
  display: flex;
  gap: 0.75rem;
}

.button {
  background: #334155;
  color: #e2e8f0;
  border: none;
  padding: 0.6rem 1.25rem;
  border-radius: 6px;
  font-size: 0.875rem;
  font-weight: 500;
  cursor: pointer;
  transition: background 0.15s;
}

.button:hover {
  background: #475569;
}

.button:focus {
  outline: none; /* suppress default */
}

